mapper.select:
SELECT s.id, s.name, s.no, s.gender, s.phone, s.id_card, s.is_college, s.address, s.degree, s.graduation_date, s.clazz_id, s.violation_count, s.violation_score, s.create_time, s.update_time, c.name AS clazz_name FROM student s LEFT JOIN clazz c ON s.clazz_id = c.id
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.clazz_id = #{clazzId}
AND s.gender = #{gender}
AND s.degree = #{degree}
ORDER BY s.id DESC LIMIT #{offset}, #{pageSize}

